(function(){"use strict";var CUR_KEY="wgp_hotnot_verdict_v1";var OWN_KEY="wgp_hotnot_verdict_own_v1";function read(key){try{var raw=localStorage.getItem(key);return raw?JSON.parse(raw):null}catch(e){return null}}function write(key,val){try{if(val==null)localStorage.removeItem(key);else localStorage.setItem(key,JSON.stringify(val))}catch(e){}}function notify(){document.dispatchEvent(new CustomEvent("wgp:taste:change",{detail:api.getEffective()}));if(window.wgpVerdictMatch&&typeof window.wgpVerdictMatch.refresh==="function"){try{window.wgpVerdictMatch.refresh()}catch(e){}}}var api={getEffective:function(){return read(CUR_KEY)},getOwn:function(){var cur=read(CUR_KEY);if(cur&&!cur.adopted)return cur;return read(OWN_KEY)},isAdopted:function(){var cur=read(CUR_KEY);return!!(cur&&cur.adopted)},adopt:function(friend){if(!friend||!friend.verdict)return false;var cur=read(CUR_KEY);if(cur&&!cur.adopted)write(OWN_KEY,cur);var slug=(friend.verdict.title||"").toLowerCase().replace(/[^a-z0-9]+/g,"-");write(CUR_KEY,{slug,title:friend.verdict.title,emoji:friend.verdict.emoji,sub:friend.verdict.sub,signature:friend.signature||[],strength:typeof friend.strength==="number"?friend.strength:null,archetype:friend.archetype||null,fromName:friend.fromName||null,adopted:true,adoptedAt:Date.now()});if(window.wgpTrack)window.wgpTrack.track("taste_adopt",{verdict:slug});notify();return true},revert:function(){var own=read(OWN_KEY);if(own){write(CUR_KEY,own);write(OWN_KEY,null)}else{write(CUR_KEY,null)}if(window.wgpTrack)window.wgpTrack.track("taste_revert");notify();return!!own},onChange:function(fn){function h(e){try{fn(e.detail)}catch(err){}}document.addEventListener("wgp:taste:change",h);return function(){document.removeEventListener("wgp:taste:change",h)}}};window.wgpTaste=api})();
